const SHEET = "data:image/png;base64,";
const SW=56, SH=56, BGW=336, BGH=224;

// ── SPRITE ────────────────────────────────────────────────────
function Spr({idx=0,active=false,color="#fff",f="",size=56}){
  const col=idx%6, row=Math.floor(idx/6);
  const sc=size/56;
  const glow=active
    ?`drop-shadow(0 0 6px ${color}) drop-shadow(0 0 14px ${color}80)`
    :"drop-shadow(0 3px 5px rgba(0,0,0,.65))";
  return <div style={{
    width:size,height:size,
    backgroundImage:`url(${SHEET})`,
    backgroundSize:`${BGW*sc}px ${BGH*sc}px`,
    backgroundPosition:`${-col*size}px ${-row*size}px`,
    backgroundRepeat:"no-repeat",
    imageRendering:"pixelated",flexShrink:0,
    filter:f?`${f} ${glow}`:glow,
    transition:"filter .2s",
  }}/>;
}

