                          <div style={{position:'absolute',top:3,right:3,fontSize:13,lineHeight:1,filter:'drop-shadow(0 2px 4px rgba(0,0,0,.65))'}}>{MUGS[a2id.charCodeAt(a2id.length-1)%MUGS.length]}</div>
